phase3.solution:
public class LoopPractice {
    public static void main(String[] args) {
        // For loop descending
        System.out.println("Counting down:");
        for (int i = 10; i >= 1; i--) {
            System.out.println(i);
        }

        // While loop sum
        int sum = 0;
        int num = 1;
        while (num <= 100) {
            sum += num;
            num++;
        }
        System.out.println("Sum of 1-100: " + sum);
    }
}
